const it = $input.item.json;
const em = it.estructura_minima || {};
const hasContact = !!(it.email || it.document_id || it.phone);
const anonimato_ok = it.is_anonymous ? false : hasContact;
const gates = {
  hechos_ok:    em.hechos_ok === true && (it.hechos || '').trim().length > 0,
  peticion_ok:  em.peticion_ok === true && (it.peticion || '').trim().length > 0,
  respeto_ok:   it.respeto_ok === true && it.is_offensive !== true,
  anonimato_ok
};
const passes_validity = gates.hechos_ok && gates.peticion_ok && gates.respeto_ok && gates.anonimato_ok;
return { ...it, gates, anonimato: !!it.is_anonymous, passes_validity };

